import React, {useState, useEffect, useImperativeHandle,forwardRef} from 'react'
import { gen12CodeId, getLng, getProfileId, getStore,  isMobile, ObjectKeys, updStore } from '../../store/Util';
import { selectCalendarObs, setObserveAppointment } from '../../store/qvamarketsSlice';

import { useDispatch, useSelector } from 'react-redux';
import { SubscribeUSer } from '../../actions/common';

export function febMaxDays(year){
  if ( (year%100!==0)){
      if((year%4===0) || (year%400===0)){
          return 29;
      }else{
          return 28;
      }
  }else{
    return 28;
  }
}

	
var monthNames = {
  "en":["January","February","March","April","May","June","July","August","September","October","November", "December"],
  "es":["Enero","Febrero","Marzo","Abril","Mayo","Junio","Julio","Agosto","Septiembre","Octubre","Noviembre", "Diciembre"]
};
var dayNames = {
  "en":["Sunday","Monday","Tuesday","Wednesday","Thrusday","Friday", "Saturday"]
};


const Calendar_appointmets = forwardRef((props,ref) => {

  const obs_cal = useSelector(selectCalendarObs)

  

  const [initialize, setInitialize] = useState(false);

  const [dateNow, set_dateNow] = useState(new Date());
  
  const [day, set_day] = useState(dateNow.getDate());

  const [data, set_data] = useState([]);
  const [obs, set_obs] = useState(0);

  const [obs_calendar, set_obs_cal] = useState(0);

  const available_byDate = (_id) => {
    let appointments_dates_shift =( getStore("AppointmentsDates") &&  getStore("AppointmentsDates")[_id] &&  getStore("AppointmentsDates")[_id]["shift"]) || {};
    let h = []
    ObjectKeys(appointments_dates_shift).map(i2 => {
      if(appointments_dates_shift[i2].isActive && (!appointments_dates_shift[i2].reserved || appointments_dates_shift[i2].reserved===getProfileId())){
        h.push(appointments_dates_shift[i2])
      }
    });
    return h
  }

  const shift_byUser = (_id) => {
    let appointments_dates_shift = (getStore("AppointmentsDates") &&  getStore("AppointmentsDates")[_id] &&  getStore("AppointmentsDates")[_id]["shift"]) || {};
    let h = []
    ObjectKeys(appointments_dates_shift).map(i2 => {
      if(appointments_dates_shift[i2].reserved===getProfileId()){
        h.push(appointments_dates_shift[i2])
      }
    });
    return h
  }

  const recerved_by_shift = (_id) => {
    let appointments_dates_shift = (getStore("AppointmentsDates") &&  getStore("AppointmentsDates")[_id] &&  getStore("AppointmentsDates")[_id]["shift"]) || {};
    let h = []
    ObjectKeys(appointments_dates_shift).map(i2 => {
      if(appointments_dates_shift[i2].reserved){
        h.push(appointments_dates_shift[i2])
      }
    });
    return h
  }
  
const renderCalendar = (month, year) => {
  
  let calob = {}

  var counter = 1;
  let week = 0;
  var dayPerMonth = ["31", ""+febMaxDays(year)+"","31","30","31","30","31","31","30","31","30","31"];

  var nextMonth = month+1; 
  // var prevMonth = month-1;
  let nxmnt = ""+(nextMonth>12?1:nextMonth) +'/1/'+(nextMonth>12?(year+1):year);

  var nextDate = new Date(nxmnt);
  var weekdays= nextDate.getDay();
  var weekdays2 = weekdays;
  var numOfDays = dayPerMonth[month];

  while (weekdays>0){
      let itm = {className:'monthPre', disable : true  }
      if(!calob[week]){
        calob[week] = []
      }
      calob[week].push(itm)
      weekdays--;
  }
  while (counter <= numOfDays){
      if (weekdays2 > 6){
          weekdays2 = 0;
          week += 1;
      }
      const year2 = dateNow.getFullYear();
      const mnt2 = dateNow.getMonth();
      let isInY = (year2 === year && mnt2 === month);
      let isDisable = !getStore('isSpaOwner') &&  counter < day && isInY;
      let _past = counter < day && isInY;
      let _id = year+"_"+month+"_"+counter;
      let appointments_dates = getStore("AppointmentsDates") &&  getStore("AppointmentsDates")[_id];
      let appointments_dates_shift = appointments_dates &&  appointments_dates["shift"];
      let date_isActive = appointments_dates &&  appointments_dates["isActive"];
      let avaAp = date_isActive && appointments_dates_shift? getStore('isSpaOwner')? recerved_by_shift(_id).length: available_byDate(_id ).length:0;
      let rdata = appointments_dates_shift?shift_byUser(_id).length:null;
      if (counter === day && isInY){
          if(!calob[week]){
            calob[week] = []
          }
          let itm = {className:'dayNow monthNow',counter:counter, available : avaAp, id: _id, hasReservation: rdata, past: _past }
          calob[week].push(itm);
      }
      else{
        
        if(!calob[week]){
          calob[week] = []
        }
        let itm = {className: "monthNow", counter:counter, disable : isDisable || !avaAp, available :avaAp, id: _id, hasReservation: rdata, past:_past }
        calob[week].push(itm)
    }
    weekdays2++;
    counter++;
  }
  return calob;
} 

const dispatch = useDispatch()


  const openTimeCard = (_idDay) => {

    isMobile() && window.scrollTo(0,0);
    updStore("time2makeAppId",null);
    updStore("openTimeCard",true)
    updStore("date2makeAppId",_idDay);
    set_obs(gen12CodeId())
    dispatch(setObserveAppointment())
  }

  useEffect(() => {
    if(!initialize){
      setInitialize(true);
      const month = dateNow.getMonth();
      const year = dateNow.getFullYear();

      let cald = renderCalendar(month,year);
      let nexcald = renderCalendar(month+1>11?0:month+1, month+1>11?year+1:year);
      let arr = [];
      arr.push({cal:cald, month:month, year: year });
      arr.push({cal:nexcald, month: month+1>11?0:month+1, year:  month+1>11?year+1:year });
      set_data(arr)
    }
    return () => {
      // 
    }
  }, [])
  


  useImperativeHandle(ref, () => ({
    drawCalendar(v) {
      const month = dateNow.getMonth();
      const year = dateNow.getFullYear();

      let cald = renderCalendar(month,year);
      let nexcald = renderCalendar(month+1>11?0:month+1, month+1>11?year+1:year);
      let arr = [];
      arr.push({cal:cald, month:month, year: year });
      arr.push({cal:nexcald, month: month+1>11?0:month+1, year:  month+1>11?year+1:year });
      set_data(arr)
    }
  }));





  if(obs_cal && obs_cal!==obs_calendar){
    set_obs_cal(obs_cal);
    const month = dateNow.getMonth();
    const year = dateNow.getFullYear();

    let cald = renderCalendar(month,year);
    let nexcald = renderCalendar(month+1>11?0:month+1, month+1>11?year+1:year);
    let arr = [];
    arr.push({cal:cald, month:month, year: year });
    arr.push({cal:nexcald, month: month+1>11?0:month+1, year:  month+1>11?year+1:year });
    set_data(arr)
  }
  
  let wksd =  {
    "en":["S","M","T","M","T","F","S"],
    "es":["D","L","M","M","J","V","S"]
  }
  return (
    <div className="calendar_wrapper" >
    {data.map((calMnth, inC)=>{
      return (
        <div className={`FyzlMe ydXJud ${inC!==0?" hgtMrg":""}`}  key={inC+"_month_cal_"+calMnth.month+"_"+calMnth.year}>
            <div className={`monthName `} >
              {`${monthNames[getLng()][calMnth.month]} ${calMnth.year}`}
            </div>
            <div className={`weekDayNames `} >
              {wksd[getLng()].map((kdI, Inw)=>{
                return (
                  <div className={`CQYfx nMqzLd `} key={kdI+"_"+Inw} >
                    {kdI}
                  </div>
                )
              })
              }
            </div>
            <div>
              {ObjectKeys(calMnth.cal).map(wk=>{
                let ttw = ObjectKeys(calMnth.cal).length - 1;
                let wper = 100;
                if(ttw===wk*1 && calMnth.cal[wk].length<7){
                  wper = calMnth.cal[wk].length/7*100;
                }
                return (
                  
                  <div className={`_dsplFlx `} style={{width:wper+"%"}} key={"_"+wk+"_week_"+calMnth.month} >
                  {calMnth.cal[wk].map((dys,_in5)=>{
                    let _id =dys['id'];
                    let isAct = getStore("date2makeAppId") === _id;
                    let cls = ` _dsplFlx ${dys['className']} ${isAct?"isAct":""} ${!dys['disable'] || getStore('isSpaOwner') ?"":"disable"} ${dys['hasReservation']?"hasReservation":""} ${dys['available']>0 || getStore('isSpaOwner') ?"":"cursor_default"}  ${dys.past?"disable":""}`
                    return (
                      <div className={cls} key={_in5+"_day_"+wk+"_mnth_"+calMnth.month} onClick={()=>(dys['available']>0 || (getStore('isSpaOwner') && !dys['past'])) && openTimeCard(_id)}>
                        <div className='lkvzbb'>
                          <div className='day_number_label'>
                            {dys['counter']}
                          </div>
                          {!dys['disable'] && dys['available']?
                            <div className={`available_appointment ${dys['available']?"pos":""}`}>
                              {dys['available']}
                            </div>
                          :null}
                        </div>
                      </div>
                    )
                  })}
                  </div>
                )
              })}
            </div>

        </div>
    ) })}
    </div>
    )
})


export default Calendar_appointmets;